    14→  async canActivate(context: ExecutionContext): Promise<boolean> {
    15→    const request = context.switchToHttp().getRequest();
    16→    const apiKey = request.headers['x-tenant-api-key'];
    17→
    18→    if (!apiKey) {
    19→      throw ExceptionFactory.create({
    20→        exceptionCode: 'auth.apiKeyRequired',
    21→        statusCode: HttpStatus.UNAUTHORIZED,
    22→        message: 'Api key is required',
    23→      });
    24→    }
    25→    const apiKeyEntity = await this.apiKeyService.getOneFull({
    26→      apiKey: apiKey,
    27→      filter: {
    28→        isActive: true,
    29→        deleted: false,
    30→      },
    31→    });
    32→    if (!apiKeyEntity) {
    33→      throw ExceptionFactory.create({
    34→        exceptionCode: 'auth.invalidApiKey',
    35→        statusCode: HttpStatus.UNAUTHORIZED,
    36→        message: 'Invalid api key',
    37→      });
    38→    }
    39→
    40→    // TODO: validate that tenant domain from origin is the same as the tenant from the api key
    41→
    42→    request.tenantId = apiKeyEntity.tenantId;
