     3→  ConflictException,
     4→  forwardRef,
     5→  Inject,
     6→  Injectable,
     7→} from '@nestjs/common';
     8→import { DATABASE_CONNECTION_TOKEN } from '@shared/database/constant';
     9→import { Db } from '@shared/database/types';
    10→import { Selectable } from 'kysely';
    11→import { IInitializeTenant } from '../types';
    12→import { TenantAccountService } from '@modules/balance/services/tenant-account.service';
    13→import { NotificationsService } from '@modules/notifications/services/notifications.service';
    14→
    15→@Injectable()
    16→export class TenantService {
    17→  constructor(
    18→    @Inject(DATABASE_CONNECTION_TOKEN) private readonly db: Db,
    19→    @Inject(forwardRef(() => TenantAccountService))
    20→    private readonly tenantAccountService: TenantAccountService,
    21→    private readonly notificationsService: NotificationsService,
    22→  ) {}
    23→
    24→  async getTenant(tenantId: number): Promise<Selectable<TenantEntity>> {
    25→    const tenant = await this.db
    26→      .selectFrom('tenant')
    27→      .selectAll()
    28→      .where('id', '=', tenantId)
    29→      .executeTakeFirst();
    30→    return tenant;
    31→  }
    32→
    33→  async initializeTenant(
    34→    input: IInitializeTenant,
    35→  ): Promise<Selectable<TenantEntity>> {
    36→    const trx = await this.db
    37→      .startTransaction()
    38→      .setIsolationLevel('serializable')
    39→      .execute();
    40→    try {
    41→      const user = await trx
    42→        .selectFrom('user')
    43→        .select('tenantId')
    44→        .where('id', '=', input.userId)
    45→        .executeTakeFirstOrThrow();
    46→
    47→      if (user.tenantId !== null) {
    48→        throw new ConflictException('User already has a tenant');
    49→      }
    50→
    51→      const tenant = await trx
    52→        .insertInto('tenant')
    53→        .values({
    54→          name: input.name,
    55→          industry: input.industry ?? null,
    56→          createdBy: input.userId,
    57→        })
    58→        .returningAll()
    59→        .executeTakeFirstOrThrow();
    60→
    61→      await trx
    62→        .updateTable('user')
    63→        .set({ tenantId: tenant.id, role: 'ADMIN' })
    64→        .where('id', '=', input.userId)
    65→        .execute();
    66→
    67→      await this.tenantAccountService.createTenantAccount(
    68→        {
    69→          tenantId: tenant.id,
    70→          name: 'Primary Account',
    71→        },
    72→        trx,
    73→      );
    74→
    75→      await trx.commit().execute();
    76→      void this.notificationsService.sendNotification(
    77→        `Tenant ${tenant.name} created`,
    78→      );
    79→      return tenant;
    80→    } catch (err) {
    81→      await trx.rollback().execute();
    82→      throw err;
    83→    }
    84→  }
    85→}
